// Ctrl+Opt+Space → toggle Vietnamese input (check before any early returns)
if eventType == .keyDown {
    let keyCode = event.getIntegerValueField(.keyboardEventKeycode)
    if keyCode == 0x31 {
        let rawFlags = event.flags.rawValue
        let ctrl = CGEventFlags.maskControl.rawValue
        let opt = CGEventFlags.maskAlternate.rawValue
        let cmd = CGEventFlags.maskCommand.rawValue
        if (rawFlags & ctrl) != 0 && (rawFlags & opt) != 0 && (rawFlags & cmd) == 0 {
            appDelegate.toggleVietnamese()
            return nil
        }
    }
}

